const input = items?.[0]?.json ?? {};

function getNodeItemJson(nodeName) {
  try {
    return $items(nodeName, 0, 0)?.[0]?.json ?? {};
  } catch (error) {
    return {};
  }
}

const createProduct = getNodeItemJson("Create Product");
const getProductData = getNodeItemJson("Get Product DATA");
const parsedImageLinksData = getNodeItemJson("string to array for image links");

// surse posibile, în ordinea priorității
const sources = [
  input?.output ?? {},
  input ?? {},
  parsedImageLinksData?.output ?? {},
  parsedImageLinksData ?? {},
  getProductData?.output ?? {},
  getProductData ?? {},
];

// helper: ia primul câmp nenul / nedefinit / nevid
function getFieldValue(key) {
  for (const src of sources) {
    if (!src || typeof src !== "object") continue;

    // cheie exactă
    if (src[key] !== undefined && src[key] !== null && src[key] !== "") {
      return src[key];
    }

    // fallback pentru chei cu spații accidentale
    const trimmedMatch = Object.keys(src).find(
      k => String(k).trim() === key
    );
    if (trimmedMatch && src[trimmedMatch] !== undefined && src[trimmedMatch] !== null && src[trimmedMatch] !== "") {
      return src[trimmedMatch];
    }
  }

  // dacă nu găsim nimic, întoarcem string gol
  return "";
}

function normalizeProductGid(raw) {
  if (raw == null || raw === "") return null;
  const value = String(raw).trim();
  if (!value) return null;

  if (value.startsWith("gid://shopify/Product/")) return value;

  const id = value.includes("/") ? value.split("/").pop() : value;
  return id ? `gid://shopify/Product/${id}` : null;
}

function normalizeMediaImageGid(raw) {
  if (raw == null || raw === "") return null;
  const value = String(raw).trim();
  if (!value) return null;

  if (
    value.startsWith("gid://shopify/MediaImage/") ||
    value.startsWith("gid://shopify/File/")
  ) {
    return value;
  }

  const id = value.includes("/") ? value.split("/").pop() : value;
  return id ? `gid://shopify/MediaImage/${id}` : null;
}

const productId = normalizeProductGid(
  createProduct?.data?.productCreate?.product?.id ??
  getFieldValue("product_id") ??
  input?.data?.productCreate?.product?.id ??
  null
);

if (!productId) {
  throw new Error("Missing product id from Create Product");
}

const NAMESPACE = "custom";

