  { key: "faq_4_q", type: "single_line_text_field" },
  { key: "faq_4_a", type: "rich_text_field" },
  { key: "rev_5_img", type: "file_reference" },
  { key: "rev_4_img", type: "file_reference" },
  { key: "rev_3_img", type: "file_reference" },
  { key: "rev_2_img", type: "file_reference" },
  { key: "rev_1_img", type: "file_reference" },
  { key: "section_3_image", type: "file_reference" },
  { key: "section_2_image", type: "file_reference" },
  { key: "section_1_image", type: "file_reference" },
];

function stripMarkdown(value) {
  if (value == null) return "";
  return String(value)
    .replace(/\*\*(.*?)\*\*/g, "$1")
    .replace(/\*(.*?)\*/g, "$1")
    .replace(/__(.*?)__/g, "$1")
    .replace(/`(.*?)`/g, "$1")
    .trim();
}

function toRichTextFieldString(value) {
  return JSON.stringify({
    type: "root",
    children: [
      {
        type: "paragraph",
        children: [
          {
            type: "text",
            value: value == null ? "" : stripMarkdown(String(value)),
          },
        ],
      },
    ],
  });
}

const fallbackImageId = normalizeMediaImageGid(
  getFieldValue("image_id")
);

function formatValue(type, rawValue) {
  if (type === "rich_text_field") {
    return toRichTextFieldString(rawValue);
  }

  if (type === "single_line_text_field") {
    return stripMarkdown(rawValue).slice(0, 255);
  }

  if (type === "file_reference") {
    const candidate = rawValue == null || rawValue === "" ? fallbackImageId : rawValue;
    return normalizeMediaImageGid(candidate);
  }

  return rawValue == null ? "" : String(rawValue);
}

function shouldIncludeMetafield(type, value) {
  // pentru imagini, trimitem doar dacă există un gid valid
  if (type === "file_reference") {
    return !!value;
  }

  // pentru celelalte, le păstrăm pe toate
  return true;
}

function buildMetafields(schema) {
  return schema
    .map(({ key, type }) => {
      const rawValue = getFieldValue(key);
      const value = formatValue(type, rawValue);

      if (!shouldIncludeMetafield(type, value)) {
        return null;
      }

      return {
        ownerId: productId,
        namespace: NAMESPACE,
        key,
        type,
        value,
      };
    })
    .filter(Boolean);
}

const firstBatch = {
  metafields: buildMetafields(firstBatchSchema),
};

const secondBatch = {
  metafields: buildMetafields(secondBatchSchema),
};

return [
  { json: { variables: firstBatch } },
  { json: { variables: secondBatch } },
];

