return items.map((item) => {
  const rawValue = item.json.link ?? item.json.url ?? "";
  const raw = String(rawValue).trim();

  let host = "";
  let path = "";
  let status_likely_product = false;
  let status_needs_fetch = true;
  let match_reason = "needs_html_validation";

  try {
    // Parse host + path with regex instead of new URL()
    const match = raw.match(/^https?:\/\/([^\/?#]+)(\/[^?#]*)?/i);

    if (!match) {
      throw new Error("Could not parse absolute http/https URL");
    }

    host = (match[1] || "").toLowerCase();
    path = (match[2] || "/").toLowerCase();

    const rules = [
      { test: /amazon\./.test(host) && /\/dp\/[a-z0-9]{10}/i.test(path), reason: "amazon_dp" },
      { test: /walmart\.com$/.test(host) && /\/ip\//.test(path), reason: "walmart_ip" },
      { test: /walmart\.ca$/.test(host) && /\/ip\//.test(path), reason: "walmartca_ip" },
      { test: /ebay\./.test(host) && /\/itm\//.test(path), reason: "ebay_itm" },
      { test: /aliexpress\./.test(host) && /^\/item\/\d+\.html$/.test(path), reason: "aliexpress_item" },
      { test: /aliexpress\./.test(host) && /^\/i\/\d+\.html$/.test(path), reason: "aliexpress_i" },
      { test: /wayfair\./.test(host) && /\/pdp\//.test(path), reason: "wayfair_pdp" },
      { test: /fruugo\./.test(host) && /\/p-\d+/.test(path), reason: "fruugo_product" },
      { test: /alibaba\./.test(host) && /\/product-detail\//.test(path), reason: "alibaba_product_detail" },
      { test: /bobshop\.co\.za$/.test(host) && /\/p\/\d+/.test(path), reason: "bobshop_product" },

      // generic fallbacks
      { test: /\/product\//.test(path), reason: "generic_product" },
      { test: /\/products\//.test(path), reason: "generic_products" },
      { test: /\/dp\//.test(path), reason: "generic_dp" },
      { test: /\/itm\//.test(path), reason: "generic_itm" },
      { test: /\/ip\//.test(path), reason: "generic_ip" },
      { test: /\/product-detail\//.test(path), reason: "generic_product_detail" },
    ];

    const matched = rules.find(r => r.test);

    if (matched) {
      status_likely_product = true;
      status_needs_fetch = false;
      match_reason = matched.reason;
    }

    return {
      json: {
        ...item.json,
        parsed_host: host,
        parsed_path: path,
        status_likely_product,
        status_needs_fetch,
        match_reason,
      }
    };
  } catch (e) {
    return {
      json: {
        ...item.json,
        debug_raw: rawValue,
        debug_raw_as_string: raw,
        parsed_host: host,
        parsed_path: path,
        error_message: e.message,
        status_likely_product: false,
        status_needs_fetch: false,
        match_reason: "invalid_url",
      }
    };
  }
});

