// Works whether input comes as:
// 1) multiple n8n items, each with one product in item.json
// 2) one n8n item containing an array in item.json

let products = [];

// Case 1: one item contains an array
if (items.length === 1 && Array.isArray(items[0].json)) {
  products = items[0].json;
}
// Case 2: normal n8n flow: multiple items
else {
  products = items.map(item => item.json);
}

// Remove unwanted fields
const cleanedProducts = products.map(({ images, URLS, ...rest }) => rest);

// Return one single merged item
return [
  {
    json: {
      products: cleanedProducts
    }
  }
];

